mapper.select:
select count(*) from wh_warehouse_apply
where bas_apply_id = #{basApplyId}
  and tenant_id = #{tenantId}
  and (del_flag = 0 or del_flag is null)


select count(*) from wh_wh_apply_ck_entry_ref
where wh_apply_id = #{whApplyId} and tenant_id = #{scopedTenantId}
  and del_flag = 0 and link_status = 1


select coalesce(sum(ref_qty), 0) from wh_wh_apply_ck_entry_ref
where wh_apply_entry_id = #{entryId} and tenant_id = #{scopedTenantId}
  and del_flag = 0 and link_status = 1


select m.id, m.tenant_id, m.apply_bill_no, m.bas_apply_id, m.bas_apply_bill_no, m.warehouse_id, m.department_id,
       m.bill_status, m.void_whole_flag, m.void_whole_by, m.void_whole_time, m.void_whole_reason,
       m.total_qty, m.total_amt, m.source_audit_date, m.del_flag,
       m.create_by, m.create_time, m.update_by, m.update_time, m.remark,
       w.id w_id, w.name w_name, w.code w_code,
       d.id d_id, d.name d_name, d.code d_code
from wh_warehouse_apply m
left join fd_warehouse w on m.warehouse_id = w.id
left join fd_department d on m.department_id = d.id

    m.tenant_id = #{scopedTenantId}
    and (m.del_flag = 0 or m.del_flag is null)

        and (m.void_whole_flag = 0 or m.void_whole_flag is null)

    and m.apply_bill_no = #{applyBillNo}
    and m.bas_apply_id = #{basApplyId}
    and m.bas_apply_bill_no = #{basApplyBillNo}
    and m.warehouse_id = #{warehouseId}
    and m.department_id = #{departmentId}
    and m.bill_status = #{billStatus}

order by m.create_time desc, m.id desc

mapper.update:
update wh_wh_apply_ck_entry_ref
set del_flag = 1, link_status = 0, update_by = #{updateBy}, update_time = now()
where ck_bill_id = #{ckBillId}
  and tenant_id = #{tenantId}
  and del_flag = 0

mapper.insert:
