    id, tenant_id, wh_apply_id, wh_apply_bill_no, wh_apply_entry_id,
    ck_bill_id, ck_bill_no, ck_entry_id, ref_qty, ref_amt, link_status, del_flag,
    create_by, create_time, remark
) values (
    #{id}, #{tenantId}, #{whApplyId}, #{whApplyBillNo}, #{whApplyEntryId},
    #{ckBillId}, #{ckBillNo}, #{ckEntryId}, #{refQty}, #{refAmt}, #{linkStatus}, #{delFlag},
    #{createBy}, #{createTime}, #{remark}
)
